args.sparql:
SELECT ?representative ?name WHERE {
  ?representative p:P39 ?position .
  ?position ps:P39 wd:Q15522368 .
  ?position pq:P768 wd:Q8991139 .
  OPTIONAL { ?position pq:P582 ?endTime }
  FILTER ( !BOUND(?endTime) )
  ?representative rdfs:label ?name .
  FILTER (lang(?name) = 'en') .
}

SELECT ?representative ?name WHERE {
  ?representative wdt:P1705 wd:Q8991139 .
  ?representative rdfs:label ?name .
  FILTER (lang(?name) = 'en')
}

SELECT ?representative ?name WHERE {
  wd:Q8991139 wdt:P1082 ?representative .
  ?representative rdfs:label ?name .
  FILTER (lang(?name) = 'en') .
}

SELECT ?representative ?name WHERE {
  ?representative p:P39/ps:P39 wd:Q15522368 ;
                pq:P768 wd:Q8991139 .
  FILTER NOT EXISTS { ?representative p:P39/pq:P582 ?endTime }
  ?representative rdfs:label ?name .
  FILTER (lang(?name) = 'en') .
} LIMIT 1

SELECT DISTINCT ?representative ?name WHERE {
  ?representative p:P39/ps:P39 wd:Q15522368 ;
                p:P39/pq:P768 wd:Q8991139 .
  FILTER NOT EXISTS { ?representative p:P39/pq:P582 ?endTime }
  ?representative rdfs:label ?name .
  FILTER (lang(?name) = 'en')
}
LIMIT 1
